import { useFormatter } from '../context/FormatterContext.js';
import type { InternalRangeItem } from '../types/range-legend.internal.js';

export const useLegendFormattedLabels = (
  items: InternalRangeItem[],
): InternalRangeItem[] => {
  const { formatter } = useFormatter();

  return items.map((item) => {
    return {
      ...item,
      labels: {
        from: formatter(+item.labels.from),
        to: formatter(+item.labels.to),
      },
    };
  });
};
